import java.util.function.*;
public class Main {
    static <T, R> Function<T, R> memoize(Function<T, R> fn) {
        var cache = new java.util.HashMap<T, R>();
        return t -> cache.computeIfAbsent(t, fn);
    }
    public static void main(String[] args) {
        Function<Integer, Integer> slowSquare = n -> {
            System.out.println("Computing " + n);
            return n * n;
        };
        Function<Integer, Integer> fastSquare = memoize(slowSquare);
        System.out.println(fastSquare.apply(5)); // computes
        System.out.println(fastSquare.apply(5)); // cached
    }
}

