import java.util.*;
import java.util.stream.*;
public class Main {
    record Student(String name, int age, double gpa) {}
    public static void main(String[] args) {
        List<Student> students = List.of(
            new Student("Alice", 20, 3.8),
            new Student("Bob", 22, 2.9),
            new Student("Carol", 19, 3.5),
            new Student("Dave", 21, 3.1)
        );
        // Filter students with GPA >= 3.5 AND age <= 21
        // Print their names sorted alphabetically
        students.stream()
            .filter(s -> s.gpa() >= 3.5 && s.age() <= 21)
            .map(Student::name)
            .sorted()
            .forEach(System.out::println);
    }
}
